#!/usr/bin/env python3
"""
Deployment automation script for CI/CD pipeline.
Installs dependencies, runs tests, and packages for deployment.
"""

import subprocess
import sys
import os
import shutil
import tarfile
import json
import logging
from datetime import datetime, timezone
from pathlib import Path

# Configure logging
logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s [%(levelname)s] %(message)s",
    handlers=[
        logging.StreamHandler(sys.stdout),
        logging.FileHandler("deployment.log"),
    ],
)
logger = logging.getLogger(__name__)

# Configuration
PROJECT_ROOT = Path(__file__).parent.resolve()
REQUIREMENTS_FILE = PROJECT_ROOT / "requirements.txt"
TEST_DIR = PROJECT_ROOT / "tests"
SRC_DIR = PROJECT_ROOT / "src"
BUILD_DIR = PROJECT_ROOT / "build"
DIST_DIR = PROJECT_ROOT / "dist"
PACKAGE_EXCLUDES = {
    "__pycache__",
    ".git",
    ".env",
    "*.pyc",
    ".pytest_cache",
    "build",
    "dist",
    "deployment.log",
    ".tox",
    ".mypy_cache",
    "node_modules",
    ".venv",
    "venv",
}


def run_command(command, description, cwd=None, env=None):
    """Run a shell command and handle errors."""
    logger.info(f"Starting: {description}")
    logger.info(f"Command: {' '.join(command)}")

    merged_env = os.environ.copy()
    if env:
        merged_env.update(env)

    try:
        result = subprocess.run(
            command,
            cwd=cwd or PROJECT_ROOT,
            env=merged_env,
            capture_output=True,
            text=True,
            timeout=300,
        )

        if result.stdout:
            for line in result.stdout.strip().split("\n"):
                logger.info(f"  stdout: {line}")

        if result.returncode != 0:
            logger.error(f"Failed: {description} (exit code {result.returncode})")
            if result.stderr:
                for line in result.stderr.strip().split("\n"):
                    logger.error(f"  stderr: {line}")
            return False

        logger.info(f"Completed: {description}")
        return True

    except subprocess.TimeoutExpired:
        logger.error(f"Timeout: {description} exceeded 300s limit")
        return False
    except FileNotFoundError as e:
        logger.error(f"Command not found: {e}")
        return False


def check_prerequisites():
    """Verify that required files and tools exist."""
    logger.info("=" * 60)
    logger.info("STEP 1: Checking prerequisites")
    logger.info("=" * 60)

    errors = []

    # Check Python version
    python_version = sys.version_info
    logger.info(f"Python version: {python_version.major}.{python_version.minor}.{python_version.micro}")
    if python_version < (3, 8):
        errors.append("Python 3.8+ is required")

    # Check requirements.txt exists
    if not REQUIREMENTS_FILE.exists():
        errors.append(f"Requirements file not found: {REQUIREMENTS_FILE}")
    else:
        logger.info(f"Found requirements file: {REQUIREMENTS_FILE}")

    # Check for test directory or test files
    test_locations = [TEST_DIR, PROJECT_ROOT / "test"]
    test_files_in_root = list(PROJECT_ROOT.glob("test_*.py"))
    has_tests = any(d.exists() for d in test_locations) or len(test_files_in_root) > 0

    if not has_tests:
        logger.warning("No test directory or test files found - tests will be skipped")
    else:
        logger.info("Test files detected")

    # Check for source code
    source_locations = [SRC_DIR, PROJECT_ROOT / "app", PROJECT_ROOT / "main.py"]
    has_source = any(p.exists() for p in source_locations)
    if not has_source:
        logger.warning("No standard source directory found (src/, app/, main.py) - will package project root")

    if errors:
        for error in errors:
            logger.error(f"Prerequisite failed: {error}")
        return False

    logger.info("All prerequisites satisfied")
    return True


def install_dependencies():
    """Install project dependencies from requirements.txt."""
    logger.info("=" * 60)
    logger.info("STEP 2: Installing dependencies")
    logger.info("=" * 60)

    # Upgrade pip first
    pip_upgrade = run_command(
        [sys.executable, "-m", "pip", "install", "--upgrade", "pip"],
        "Upgrading pip",
    )
    if not pip_upgrade:
        logger.warning("pip upgrade failed, continuing with current version")

    # Install production dependencies
    success = run_command(
        [
            sys.executable, "-m", "pip", "install",
            "-r", str(REQUIREMENTS_FILE),
            "--no-cache-dir",
            "--quiet",
        ],
        "Installing production dependencies from requirements.txt",
    )
    if not success:
        return False

    # Install test dependencies if test requirements exist
    test_requirements = PROJECT_ROOT / "requirements-test.txt"
    dev_requirements = PROJECT_ROOT / "requirements-dev.txt"

    for req_file in [test_requirements, dev_requirements]:
        if req_file.exists():
            result = run_command(
                [
                    sys.executable, "-m", "pip", "install",
                    "-r", str(req_file),
                    "--no-cache-dir",
                    "--quiet",
                ],
                f"Installing dependencies from {req_file.name}",
            )
            if not result:
                logger.warning(f"Failed to install {req_file.name}, continuing anyway")

    # Ensure pytest is available for testing
    run_command(
        [sys.executable, "-m", "pip", "install", "pytest", "--quiet"],
        "Ensuring pytest is available",
    )

    # Verify installation by listing installed packages
    run_command(
        [sys.executable, "-m", "pip", "freeze"],
        "Listing installed packages",
    )

    logger.info("Dependencies installed successfully")
    return True


def run_linting():
    """Run optional linting checks if tools are available."""
    logger.info("-" * 40)
    logger.info("Running optional lint checks")
    logger.info("-" * 40)

    # Try flake8
    flake8_result = run_command(
        [sys.executable, "-m", "flake8", "--count", "--max-line-length=120",
         "--statistics", "--exclude=build,dist,venv,.venv", "."],
        "Running flake8 lint check",
    )
    if not flake8_result:
        logger.warning("flake8 not available or found issues - continuing")

    return True  # Linting is non-blocking


def run_tests():
    """Run the project test suite."""
    logger.info("=" * 60)
    logger.info("STEP 3: Running tests")
    logger.info("=" * 60)

    # Determine test paths
    test_paths = []
    if TEST_DIR.exists():
        test_paths.append(str(TEST_DIR))
    if (PROJECT_ROOT / "test").exists():
        test_paths.append(str(PROJECT_ROOT / "test"))

    # Also check for test files in project root
    root_test_files = list(PROJECT_ROOT.glob("test_*.py"))
    test_paths.extend(str(f) for f in root_test_files)

    if not test_paths:
        logger.warning("No test directory or test files found - skipping tests")
        return True

    # Run optional linting first
    run_linting()

    # Build pytest command
    pytest_args = [
        sys.executable, "-m", "pytest",
        *test_paths,
        "-v",
        "--tb=short",
        "--strict-markers",
        "-x",  # Stop on first failure for fast CI feedback
        "--timeout=60",  # Per-test timeout if pytest-timeout is installed
    ]

    # Add JUnit XML report for CI systems
    junit_report = BUILD_DIR / "test-results.xml"
    BUILD_DIR.mkdir(parents=True, exist_ok=True)
    pytest_args.extend(["--junitxml", str(junit_report)])

    # Add coverage if available
    try:
        import coverage  # noqa: F401
        pytest_args.extend([
            "--cov=src",
            "--cov-report=term-missing",
            "--cov-report=html:build/coverage-html",
            "--cov-fail-under=70",
        ])
        logger.info("Coverage reporting enabled (minimum 70%)")
    except ImportError:
        logger.info("Coverage not installed - skipping coverage report")

    success = run_command(
        pytest_args,
        "Running test suite with pytest",
        env={"PYTHONDONTWRITEBYTECODE": "1", "TESTING": "1"},
    )

    if not success:
        logger.error("Test suite FAILED - aborting deployment")
        return False

    logger.info("All tests passed successfully")
    return True


def should_exclude(path, root):
    """Check if a path should be excluded from the package."""
    rel = path.relative_to(root)
    parts = rel.parts

    for part in parts:
        if part in PACKAGE_EXCLUDES:
            return True
        for pattern in PACKAGE_EXCLUDES:
            if "*" in pattern and part.endswith(pattern.replace("*", "")):
                return True

    return False


def create_package():
    """Package the application for deployment."""
    logger.info("=" * 60)
    logger.info("STEP 4: Packaging for deployment")
    logger.info("=" * 60)

    # Clean previous builds
    for directory in [BUILD_DIR, DIST_DIR]:
        if directory.exists():
            logger.info(f"Cleaning {directory}")
            shutil.rmtree(directory)
        directory.mkdir(parents=True, exist_ok=True)

    # Generate build metadata
    timestamp = datetime.now(timezone.utc).strftime("%Y%m%d%H%M%S")
    git_sha = "unknown"
    try:
        result = subprocess.run(
            ["git", "rev-parse", "--short", "HEAD"],
            capture_output=True, text=True, cwd=PROJECT_ROOT,
        )
        if result.returncode == 0:
            git_sha = result.stdout.strip()
    except FileNotFoundError:
        logger.warning("git not available - using 'unknown' for commit SHA")

    try:
        result = subprocess.run(
            ["git", "rev-parse", "--abbrev-ref", "HEAD"],
            capture_output=True, text=True, cwd=PROJECT_ROOT,
        )
        git_branch = result.stdout.strip() if result.returncode == 0 else "unknown"
    except FileNotFoundError:
        git_branch = "unknown"

    package_name = f"app-{timestamp}-{git_sha}"

    # Write build metadata
    metadata = {
        "package_name": package_name,
        "build_timestamp": datetime.now(timezone.utc).isoformat(),
        "git_commit": git_sha,
        "git_branch": git_branch,
        "python_version": f"{sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}",
        "builder": os.environ.get("USER", os.environ.get("USERNAME", "ci")),
        "ci_build_id": os.environ.get("BUILD_ID", os.environ.get("CI_JOB_ID", "local")),
    }

    metadata_file = BUILD_DIR / "build-metadata.json"
    with open(metadata_file, "w") as f:
        json.dump(metadata, f, indent=2)
    logger.info(f"Build metadata written to {metadata_file}")

    # Copy requirements.txt to build
    shutil.copy2(REQUIREMENTS_FILE, BUILD_DIR / "requirements.txt")

    # Install production dependencies to build directory
    vendor_dir = BUILD_DIR / "vendor"
    success = run_command(
        [
            sys.executable, "-m", "pip", "install",
            "-r", str(REQUIREMENTS_FILE),
            "--target", str(vendor_dir),
            "--no-cache-dir",
            "--quiet",
        ],
        "Installing production dependencies into package",
    )
    if not success:
        logger.error("Failed to vendor dependencies")
        return False

    # Copy source code to build
    source_copied = False
    for source_dir in [SRC_DIR, PROJECT_ROOT / "app"]:
        if source_dir.exists():
            dest = BUILD_DIR / source_dir.name
            shutil.copytree(
                source_dir, dest,
                ignore=shutil.ignore_patterns(*PACKAGE_EXCLUDES),
            )
            logger.info(f"Copied source directory: {source_dir.name}")
            source_copied = True
            break

    if not source_copied:
        # Copy Python files from project root
        for py_file in PROJECT_ROOT.glob("*.py"):
            if py_file.name.startswith("test_"):
                continue
            shutil.copy2(py_file, BUILD_DIR / py_file.name)
            logger.info(f"Copied: {py_file.name}")

    # Copy configuration files if they exist
    config_files = [
        "config.py", "config.yaml", "config.yml", "config.json",
        ".env.example", "Procfile", "Dockerfile", "docker-compose.yml",
        "gunicorn.conf.py", "wsgi.py", "asgi.py", "manage.py",
        "alembic.ini", "setup.py", "setup.cfg", "pyproject.toml",
    ]
    for config_file in config_files:
        config_path = PROJECT_ROOT / config_file
        if config_path.exists():
            shutil.copy2(config_path, BUILD_DIR / config_file)
            logger.info(f"Included config: {config_file}")

    # Copy additional directories (e.g., migrations, templates, static)
    extra_dirs = ["migrations", "templates", "static", "config", "scripts", "alembic"]
    for dir_name in extra_dirs:
        dir_path = PROJECT_ROOT / dir_name
        if dir_path.exists():
            shutil.copytree(
                dir_path, BUILD_DIR / dir_name,
                ignore=shutil.ignore_patterns(*PACKAGE_EXCLUDES),
            )
            logger.info(f"Included directory: {dir_name}")

    # Create tarball
    tarball_name = f"{package_name}.tar.gz"
    tarball_path = DIST_DIR / tarball_name

    with tarfile.open(tarball_path, "w:gz") as tar:
        tar.add(BUILD_DIR, arcname=package_name)

    tarball_size_mb = tarball_path.stat().st_size / (1024 * 1024)
    logger.info(f"Package created: {tarball_path}")
    logger.info(f"Package size: {tarball_size_mb:.2f} MB")

    # Also write a manifest of included files
    manifest_path = DIST_DIR / f"{package_name}-manifest.txt"
    with open(manifest_path, "w") as f:
        for root, dirs, files in os.walk(BUILD_DIR):
            for file in sorted(files):
                filepath = Path(root) / file
                rel_path = filepath.relative_to(BUILD_DIR)
                f.write(f"{rel_path}\n")
    logger.info(f"Manifest written to: {manifest_path}")

    # Write deployment info for downstream CI/CD steps
    deploy_info = {
        **metadata,
        "artifact_path": str(tarball_path),
        "artifact_name": tarball_name,
        "artifact_size_bytes": tarball_path.stat().st_size,
    }
    deploy_info_path = DIST_DIR / "deploy-info.json"
    with open(deploy_info_path, "w") as f:
        json.dump(deploy_info, f, indent=2)

    logger.info("Packaging completed successfully")
    return True


def cleanup():
    """Clean up build artifacts (keep dist)."""
    logger.info("Cleaning up intermediate build files")
    if BUILD_DIR.exists():
        shutil.rmtree(BUILD_DIR)
        logger.info(f"Removed: {BUILD_DIR}")


def main():
    """Main deployment pipeline orchestrator."""
    logger.info("=" * 60)
    logger.info("DEPLOYMENT PIPELINE STARTED")
    logger.info(f"Project root: {PROJECT_ROOT}")
    logger.info(f"Timestamp: {datetime.now(timezone.utc).isoformat()}")
    logger.info("=" * 60)

    steps = [
        ("Prerequisites Check", check_prerequisites),
        ("Install Dependencies", install_dependencies),
        ("Run Tests", run_tests),
        ("Package Application", create_package),
    ]

    for step_name, step_func in steps:
        try:
            success = step_func()
        except Exception as e:
            logger.exception(f"Unexpected error in '{step_name}': {e}")
            success = False

        if not success:
            logger.error("=" * 60)
            logger.error(f"DEPLOYMENT PIPELINE FAILED at step: {step_name}")
            logger.error("=" * 60)
            sys.exit(1)

    # Optional cleanup of intermediate build artifacts
    cleanup()

    logger.info("=" * 60)
    logger.info("DEPLOYMENT PIPELINE COMPLETED SUCCESSFULLY")
    logger.info(f"Artifacts available in: {DIST_DIR}")
    logger.info("=" * 60)

    # List final artifacts
    if DIST_DIR.exists():
        for artifact in sorted(DIST_DIR.iterdir()):
            size = artifact.stat().st_size
            logger.info(f"  {artifact.name} ({size:,} bytes)")

    sys.exit(0)


if __name__ == "__main__":
    main()